Add key file cleanup to the failure path:

if new_thumbprint is None:
    logger.error("CA cert install failed after restart — proxy running without trusted CA")
    # Delete newly generated key files before abandoning restart
    try:
        delete_ca_key_files(confdir)
        delete_ca_public_cert(confdir)
    except Exception as cleanup_err:
        logger.warning("Failed to delete CA key files after install failure: %s", cleanup_err)
    try:
        new_master.shutdown()
    except Exception:
        pass
    return None, None

Save the old thumbprint before restarting and retry uninstall at least once on failure, or record orphaned thumbprints in state for cleanup on next startup:

old_thumbprint = state.ca_thumbprint
try:
    _uninstall(thumbprint=old_thumbprint)
except Exception as e:
    logger.warning("Failed to uninstall old CA (thumbprint: %s): %s", old_thumbprint[:12], e)
    # Record for cleanup on next startup
    if not hasattr(state, 'orphaned_thumbprints'):
        state.orphaned_thumbprints = []
    state.orphaned_thumbprints.append(old_thumbprint)
